#include <iostream>

class Temperature {
    int m_celsius{};
public:
    Temperature(int c) : m_celsius{c} {}
    int celsius() const { return m_celsius; }

    friend Temperature operator+(const Temperature& a, const Temperature& b);
    friend Temperature operator-(const Temperature& a, const Temperature& b);
};

Temperature operator+(const Temperature& a, const Temperature& b) {
    return Temperature{a.m_celsius + b.m_celsius};
}

Temperature operator-(const Temperature& a, const Temperature& b) {
    return Temperature{a.m_celsius - b.m_celsius};
}

int main() {
    int va, vb;
    std::cin >> va >> vb;
    Temperature a{va}, b{vb};
    Temperature s = a + b;
    Temperature d = a - b;
    std::cout << "Sum: " << s.celsius() << "\n";
    std::cout << "Diff: " << d.celsius() << "\n";
    return 0;
}

