solution_code:
#include <iostream>

int clamp255(int v) { return v <= 255 ? v : 255; }

class Pixel {
    int m_r{}, m_g{}, m_b{};
public:
    Pixel(int r, int g, int b) : m_r{r}, m_g{g}, m_b{b} {}
    int r() const { return m_r; }
    int g() const { return m_g; }
    int b() const { return m_b; }

    friend Pixel operator*(const Pixel& p, int scale);
    friend Pixel operator*(int scale, const Pixel& p);
};

Pixel operator*(const Pixel& p, int scale) {
    return Pixel{clamp255(p.m_r * scale), clamp255(p.m_g * scale), clamp255(p.m_b * scale)};
}

Pixel operator*(int scale, const Pixel& p) {
    return p * scale;
}

int main() {
    int r, g, b, s;
    std::cin >> r >> g >> b;
    std::cin >> s;
    Pixel px{r, g, b};
    Pixel result = px * s;
    std::cout << result.r() << " " << result.g() << " " << result.b() << "\n";
    return 0;
}
